async def main():
    async with async_session_factory() as db:
        # 1. Get or create FY2026 budget version
        result = await db.execute(
            select(BudgetVersion).where(
                BudgetVersion.fy_year == 2026,
                BudgetVersion.name.like("%FY2026%Site%")
            )
        )
        version = result.scalar_one_or_none()
        
        if not version:
            version = BudgetVersion(
                id=uuid.uuid4(),
                name="FY2026 Budget (Site-level import)",
                fy_year=2026,
                version_type=VersionType.budget,
                status=VersionStatus.draft,
            )
            db.add(version)
            await db.flush()
            print(f"Created budget version: {version.id}")
        else:
            print(f"Using existing budget version: {version.id}")
        
        # 2. Get SH entity (most sites are under SH)
        result = await db.execute(select(Entity).where(Entity.code == 'SH'))
        sh_entity = result.scalar_one_or_none()
        if not sh_entity:
            raise ValueError("SH entity not found — run seed_initial.py first")
        
        # 3. Upsert locations
        location_map = {}
        for site_meta in SITES:
            result = await db.execute(
                select(Location).where(Location.name == site_meta["name"])
            )
            location = result.scalar_one_or_none()
            if not location:
                location = Location(
                    id=uuid.uuid4(),
                    code=site_meta["short"].upper().replace(" ", "_")[:20],
                    name=site_meta["name"],
                    entity_id=sh_entity.id,
                    state=site_meta["state"],
                    is_active=True,
                )
                db.add(location)
                await db.flush()
                print(f"  Created location: {site_meta['name']}")
            location_map[site_meta["name"]] = location
        
        # 4. Get periods
        result = await db.execute(
            select(Period).where(Period.fy_year == 2026)
        )
        periods = {(p.fy_year, p.fy_month): p for p in result.scalars().all()}
        
        # 5. Insert site_budget_entries
        # Delete existing entries for this version first
        await db.execute(
            text("DELETE FROM site_budget_entries WHERE version_id = :vid"),
            {"vid": str(version.id)}
        )
        
        entries_created = 0
        for site_name, monthly_data in BUDGET_DATA.items():
            location = location_map.get(site_name)
            if not location:
                print(f"  WARNING: No location found for {site_name}")
                continue
            
            for (fy_year, fy_month), financials in monthly_data.items():
                period = periods.get((fy_year, fy_month))
                if not period:
                    print(f"  WARNING: No period for FY{fy_year} M{fy_month:02d}")
                    continue
                
                # Map financials to model line items
                line_items = {
                    "revenue": financials.get("revenue", 0),
                    "cogs": financials.get("cogs", 0),
                    "labour": (financials.get("labour", 0) + financials.get("hq_labour", 0)),
                    "general": (financials.get("general", 0) + financials.get("other_hq", 0)),
                    "rm": financials.get("rm", 0),
                    "utilities": financials.get("utilities", 0),
                    "rent": financials.get("rent", 0),
                    "it": financials.get("it", 0),
                    "advertising": financials.get("advertising", 0),
                    # Operational drivers
                    "pet_days_total": financials.get("pet_days_total", 0),
                    "pet_days_boarding": financials.get("pet_days_boarding", 0),
                    "pet_days_daycare": financials.get("pet_days_daycare", 0),
                    "pet_days_grooming": financials.get("pet_days_grooming", 0),
                    "pet_days_training": financials.get("pet_days_training", 0),
                    "pet_days_wash": financials.get("pet_days_wash", 0),
                    "labour_hours": financials.get("labour_hours", 0),
                }
                
                for line_item, amount in line_items.items():
                    if amount == 0:
                        continue
                    entry = SiteBudgetEntry(
                        id=uuid.uuid4(),
                        version_id=version.id,
                        location_id=location.id,
                        model_line_item=line_item,
                        week_id=None,  # monthly grain — no weekly breakdown yet
                        amount=Decimal(str(round(amount, 2))),
                        driver_type=SiteBudgetDriverType.manual,
                        driver_params={
                            "source": "excel_import",
                            "fy_year": fy_year,
                            "fy_month": fy_month,
                            "period_id": str(period.id),
                        },
                    )
                    db.add(entry)
                    entries_created += 1
        
        await db.commit()
        print(f"\nDone. Created {entries_created} site budget entries across 38 sites x 12 months.")
        print(f"Budget version ID: {version.id}")
        print("\nNext: run the site rollup service to aggregate to entity level and trigger model calculation.")

if __name__ == "__main__":
    asyncio.run(main())
